-- 扩充古诗库：新增适合儿童/小学启蒙的未录入古诗。
-- 注意：data/poems.seed.json 同步包含这些记录，供新库初始化使用。
INSERT INTO poems (
    id, title, author, dynasty, content_json, pinyin, translation, story, parent_guide, difficulty, level, tags_json, season, audio_url, image_url, video_available, card_unlocked, annotated_content_json
) VALUES
    (101, '登科后', '孟郊', '唐', '昔日龌龊不足夸，今朝放荡思无涯。春风得意马蹄疾，一日看尽长安花。', '', '登科后描写了春天、喜悦等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人孟郊的作品。读的时候可以先抓住“春天、喜悦、人生”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“春天、喜悦、人生”主题。', 2, 2, '["春天", "喜悦", "人生"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (102, '劝学', '颜真卿', '唐', '三更灯火五更鸡，正是男儿读书时。黑发不知勤学早，白首方悔读书迟。', '', '劝学描写了勤学、惜时等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人颜真卿的作品。读的时候可以先抓住“勤学、惜时、成长”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“勤学、惜时、成长”主题。', 2, 2, '["勤学", "惜时", "成长"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (103, '金缕衣', '杜秋娘', '唐', '劝君莫惜金缕衣，劝君惜取少年时。花开堪折直须折，莫待无花空折枝。', '', '金缕衣描写了惜时、成长等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜秋娘的作品。读的时候可以先抓住“惜时、成长、花”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“惜时、成长、花”主题。', 2, 2, '["惜时", "成长", "花"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (104, '剑客', '贾岛', '唐', '十年磨一剑，霜刃未曾试。今日把示君，谁有不平事。', '', '剑客描写了志向、侠义等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人贾岛的作品。读的时候可以先抓住“志向、侠义、品格”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“志向、侠义、品格”主题。', 2, 2, '["志向", "侠义", "品格"]', 'winter', NULL, NULL, FALSE, FALSE, '[]'),
    (105, '题诗后', '贾岛', '唐', '两句三年得，一吟双泪流。知音如不赏，归卧故山秋。', '', '题诗后描写了勤奋、写作等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人贾岛的作品。读的时候可以先抓住“勤奋、写作、秋天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“勤奋、写作、秋天”主题。', 3, 3, '["勤奋", "写作", "秋天"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (106, '农家', '颜仁郁', '唐', '半夜呼儿趁晓耕，羸牛无力渐艰行。时人不识农家苦，将谓田中谷自生。', '', '农家描写了劳动、农事等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人颜仁郁的作品。读的时候可以先抓住“劳动、农事、节约”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“劳动、农事、节约”主题。', 2, 2, '["劳动", "农事", "节约"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (107, '蚕妇', '张俞', '宋', '昨日入城市，归来泪满巾。遍身罗绮者，不是养蚕人。', '', '蚕妇描写了劳动、悲悯等画面或情感，适合孩子先从画面理解诗意。', '这首诗是宋代诗人张俞的作品。读的时候可以先抓住“劳动、悲悯、生活”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“劳动、悲悯、生活”主题。', 2, 2, '["劳动", "悲悯", "生活"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (108, '陶者', '梅尧臣', '宋', '陶尽门前土，屋上无片瓦。十指不沾泥，鳞鳞居大厦。', '', '陶者描写了劳动、悲悯等画面或情感，适合孩子先从画面理解诗意。', '这首诗是宋代诗人梅尧臣的作品。读的时候可以先抓住“劳动、悲悯、生活”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“劳动、悲悯、生活”主题。', 2, 2, '["劳动", "悲悯", "生活"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (109, '乡村四月', '翁卷', '宋', '绿遍山原白满川，子规声里雨如烟。乡村四月闲人少，才了蚕桑又插田。', '', '乡村四月描写了乡村、劳动等画面或情感，适合孩子先从画面理解诗意。', '这首诗是宋代诗人翁卷的作品。读的时候可以先抓住“乡村、劳动、春天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“乡村、劳动、春天”主题。', 2, 2, '["乡村", "劳动", "春天"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (110, '约客', '赵师秀', '宋', '黄梅时节家家雨，青草池塘处处蛙。有约不来过夜半，闲敲棋子落灯花。', '', '约客描写了夏天、雨等画面或情感，适合孩子先从画面理解诗意。', '这首诗是宋代诗人赵师秀的作品。读的时候可以先抓住“夏天、雨、生活”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“夏天、雨、生活”主题。', 2, 2, '["夏天", "雨", "生活"]', 'summer', NULL, NULL, FALSE, FALSE, '[]'),
    (111, '秋夕', '杜牧', '唐', '银烛秋光冷画屏，轻罗小扇扑流萤。天阶夜色凉如水，卧看牵牛织女星。', '', '秋夕描写了秋天、夜晚等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜牧的作品。读的时候可以先抓住“秋天、夜晚、星空”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“秋天、夜晚、星空”主题。', 2, 2, '["秋天", "夜晚", "星空"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (112, '赤壁', '杜牧', '唐', '折戟沉沙铁未销，自将磨洗认前朝。东风不与周郎便，铜雀春深锁二乔。', '', '赤壁描写了历史、战争等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜牧的作品。读的时候可以先抓住“历史、战争、哲理”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“历史、战争、哲理”主题。', 3, 3, '["历史", "战争", "哲理"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (113, '赠别', '杜牧', '唐', '多情却似总无情，唯觉樽前笑不成。蜡烛有心还惜别，替人垂泪到天明。', '', '赠别描写了送别、友情等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜牧的作品。读的时候可以先抓住“送别、友情、夜晚”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“送别、友情、夜晚”主题。', 3, 3, '["送别", "友情", "夜晚"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (114, '寄扬州韩绰判官', '杜牧', '唐', '青山隐隐水迢迢，秋尽江南草未凋。二十四桥明月夜，玉人何处教吹箫。', '', '寄扬州韩绰判官描写了秋天、月夜等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜牧的作品。读的时候可以先抓住“秋天、月夜、江南”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“秋天、月夜、江南”主题。', 3, 3, '["秋天", "月夜", "江南"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (115, '嫦娥', '李商隐', '唐', '云母屏风烛影深，长河渐落晓星沉。嫦娥应悔偷灵药，碧海青天夜夜心。', '', '嫦娥描写了月夜、神话等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李商隐的作品。读的时候可以先抓住“月夜、神话、想象”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“月夜、神话、想象”主题。', 2, 2, '["月夜", "神话", "想象"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (116, '无题', '李商隐', '唐', '相见时难别亦难，东风无力百花残。春蚕到死丝方尽，蜡炬成灰泪始干。', '', '无题描写了离别、春天等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李商隐的作品。读的时候可以先抓住“离别、春天、情感”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“离别、春天、情感”主题。', 3, 3, '["离别", "春天", "情感"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (117, '霜月', '李商隐', '唐', '初闻征雁已无蝉，百尺楼高水接天。青女素娥俱耐冷，月中霜里斗婵娟。', '', '霜月描写了秋天、月夜等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李商隐的作品。读的时候可以先抓住“秋天、月夜、想象”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“秋天、月夜、想象”主题。', 3, 3, '["秋天", "月夜", "想象"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (118, '贾生', '李商隐', '唐', '宣室求贤访逐臣，贾生才调更无伦。可怜夜半虚前席，不问苍生问鬼神。', '', '贾生描写了历史、哲理等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李商隐的作品。读的时候可以先抓住“历史、哲理、家国”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“历史、哲理、家国”主题。', 3, 3, '["历史", "哲理", "家国"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (119, '逢雪宿芙蓉山主人', '刘长卿', '唐', '日暮苍山远，天寒白屋贫。柴门闻犬吠，风雪夜归人。', '', '逢雪宿芙蓉山主人描写了冬天、雪等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人刘长卿的作品。读的时候可以先抓住“冬天、雪、山村”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“冬天、雪、山村”主题。', 1, 1, '["冬天", "雪", "山村"]', 'winter', NULL, NULL, FALSE, FALSE, '[]'),
    (120, '送灵澈上人', '刘长卿', '唐', '苍苍竹林寺，杳杳钟声晚。荷笠带斜阳，青山独归远。', '', '送灵澈上人描写了送别、山林等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人刘长卿的作品。读的时候可以先抓住“送别、山林、夕阳”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“送别、山林、夕阳”主题。', 2, 2, '["送别", "山林", "夕阳"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (121, '送上人', '刘长卿', '唐', '孤云将野鹤，岂向人间住。莫买沃洲山，时人已知处。', '', '送上人描写了送别、山林等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人刘长卿的作品。读的时候可以先抓住“送别、山林、隐逸”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“送别、山林、隐逸”主题。', 3, 3, '["送别", "山林", "隐逸"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (122, '渡汉江', '宋之问', '唐', '岭外音书断，经冬复历春。近乡情更怯，不敢问来人。', '', '渡汉江描写了思乡、春天等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人宋之问的作品。读的时候可以先抓住“思乡、春天、旅途”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“思乡、春天、旅途”主题。', 2, 2, '["思乡", "春天", "旅途"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (123, '杂诗', '王维', '唐', '君自故乡来，应知故乡事。来日绮窗前，寒梅著花未。', '', '杂诗描写了思乡、梅花等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王维的作品。读的时候可以先抓住“思乡、梅花、冬天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“思乡、梅花、冬天”主题。', 1, 1, '["思乡", "梅花", "冬天"]', 'winter', NULL, NULL, FALSE, FALSE, '[]'),
    (124, '送别', '王维', '唐', '山中相送罢，日暮掩柴扉。春草明年绿，王孙归不归。', '', '送别描写了送别、春天等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王维的作品。读的时候可以先抓住“送别、春天、山林”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“送别、春天、山林”主题。', 1, 1, '["送别", "春天", "山林"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (125, '九月九日忆山东兄弟', '王维', '唐', '独在异乡为异客，每逢佳节倍思亲。遥知兄弟登高处，遍插茱萸少一人。', '', '九月九日忆山东兄弟描写了思乡、节日等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王维的作品。读的时候可以先抓住“思乡、节日、亲情”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“思乡、节日、亲情”主题。', 1, 1, '["思乡", "节日", "亲情"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (126, '鸟鸣涧', '王维', '唐', '人闲桂花落，夜静春山空。月出惊山鸟，时鸣春涧中。', '', '鸟鸣涧描写了春天、山水等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王维的作品。读的时候可以先抓住“春天、山水、月夜”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“春天、山水、月夜”主题。', 1, 1, '["春天", "山水", "月夜"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (127, '竹里馆', '王维', '唐', '独坐幽篁里，弹琴复长啸。深林人不知，明月来相照。', '', '竹里馆描写了月夜、山林等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王维的作品。读的时候可以先抓住“月夜、山林、音乐”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“月夜、山林、音乐”主题。', 1, 1, '["月夜", "山林", "音乐"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (128, '送元二使安西', '王维', '唐', '渭城朝雨浥轻尘，客舍青青柳色新。劝君更尽一杯酒，西出阳关无故人。', '', '送元二使安西描写了送别、友情等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王维的作品。读的时候可以先抓住“送别、友情、春天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“送别、友情、春天”主题。', 2, 2, '["送别", "友情", "春天"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (129, '山中', '王维', '唐', '荆溪白石出，天寒红叶稀。山路元无雨，空翠湿人衣。', '', '山中描写了山水、秋天等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王维的作品。读的时候可以先抓住“山水、秋天、冬天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“山水、秋天、冬天”主题。', 2, 2, '["山水", "秋天", "冬天"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (130, '画', '王维', '唐', '远看山有色，近听水无声。春去花还在，人来鸟不惊。', '', '画描写了山水、儿童等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王维的作品。读的时候可以先抓住“山水、儿童、春天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“山水、儿童、春天”主题。', 1, 1, '["山水", "儿童", "春天"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (131, '独坐敬亭山', '李白', '唐', '众鸟高飞尽，孤云独去闲。相看两不厌，只有敬亭山。', '', '独坐敬亭山描写了山水、孤独等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李白的作品。读的时候可以先抓住“山水、孤独、哲理”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“山水、孤独、哲理”主题。', 1, 1, '["山水", "孤独", "哲理"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (132, '秋浦歌', '李白', '唐', '白发三千丈，缘愁似个长。不知明镜里，何处得秋霜。', '', '秋浦歌描写了秋天、想象等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李白的作品。读的时候可以先抓住“秋天、想象、人生”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“秋天、想象、人生”主题。', 2, 2, '["秋天", "想象", "人生"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (133, '夜宿山寺', '李白', '唐', '危楼高百尺，手可摘星辰。不敢高声语，恐惊天上人。', '', '夜宿山寺描写了想象、星空等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李白的作品。读的时候可以先抓住“想象、星空、山寺”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“想象、星空、山寺”主题。', 1, 1, '["想象", "星空", "山寺"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (134, '峨眉山月歌', '李白', '唐', '峨眉山月半轮秋，影入平羌江水流。夜发清溪向三峡，思君不见下渝州。', '', '峨眉山月歌描写了月夜、秋天等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李白的作品。读的时候可以先抓住“月夜、秋天、旅行”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“月夜、秋天、旅行”主题。', 2, 2, '["月夜", "秋天", "旅行"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (135, '山中问答', '李白', '唐', '问余何意栖碧山，笑而不答心自闲。桃花流水窅然去，别有天地非人间。', '', '山中问答描写了山水、春天等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李白的作品。读的时候可以先抓住“山水、春天、闲适”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“山水、春天、闲适”主题。', 2, 2, '["山水", "春天", "闲适"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (136, '客中行', '李白', '唐', '兰陵美酒郁金香，玉碗盛来琥珀光。但使主人能醉客，不知何处是他乡。', '', '客中行描写了友情、饮酒等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李白的作品。读的时候可以先抓住“友情、饮酒、旅行”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“友情、饮酒、旅行”主题。', 3, 3, '["友情", "饮酒", "旅行"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (137, '春夜洛城闻笛', '李白', '唐', '谁家玉笛暗飞声，散入春风满洛城。此夜曲中闻折柳，何人不起故园情。', '', '春夜洛城闻笛描写了思乡、春天等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人李白的作品。读的时候可以先抓住“思乡、春天、音乐”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“思乡、春天、音乐”主题。', 2, 2, '["思乡", "春天", "音乐"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (138, '逢入京使', '岑参', '唐', '故园东望路漫漫，双袖龙钟泪不干。马上相逢无纸笔，凭君传语报平安。', '', '逢入京使描写了思乡、边塞等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人岑参的作品。读的时候可以先抓住“思乡、边塞、亲情”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“思乡、边塞、亲情”主题。', 2, 2, '["思乡", "边塞", "亲情"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (139, '白雪歌送武判官归京', '岑参', '唐', '北风卷地白草折，胡天八月即飞雪。忽如一夜春风来，千树万树梨花开。', '', '白雪歌送武判官归京描写了冬天、边塞等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人岑参的作品。读的时候可以先抓住“冬天、边塞、送别”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“冬天、边塞、送别”主题。', 3, 3, '["冬天", "边塞", "送别"]', 'winter', NULL, NULL, FALSE, FALSE, '[]'),
    (140, '别董大', '高适', '唐', '千里黄云白日曛，北风吹雁雪纷纷。莫愁前路无知己，天下谁人不识君。', '', '别董大描写了送别、友情等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人高适的作品。读的时候可以先抓住“送别、友情、冬天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“送别、友情、冬天”主题。', 2, 2, '["送别", "友情", "冬天"]', 'winter', NULL, NULL, FALSE, FALSE, '[]'),
    (141, '塞下曲', '卢纶', '唐', '月黑雁飞高，单于夜遁逃。欲将轻骑逐，大雪满弓刀。', '', '塞下曲描写了边塞、战争等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人卢纶的作品。读的时候可以先抓住“边塞、战争、冬天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“边塞、战争、冬天”主题。', 2, 2, '["边塞", "战争", "冬天"]', 'winter', NULL, NULL, FALSE, FALSE, '[]'),
    (142, '塞下曲其二', '卢纶', '唐', '林暗草惊风，将军夜引弓。平明寻白羽，没在石棱中。', '', '塞下曲其二描写了边塞、战争等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人卢纶的作品。读的时候可以先抓住“边塞、战争、勇敢”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“边塞、战争、勇敢”主题。', 2, 2, '["边塞", "战争", "勇敢"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (143, '寒食', '韩翃', '唐', '春城无处不飞花，寒食东风御柳斜。日暮汉宫传蜡烛，轻烟散入五侯家。', '', '寒食描写了节日、春天等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人韩翃的作品。读的时候可以先抓住“节日、春天、历史”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“节日、春天、历史”主题。', 2, 2, '["节日", "春天", "历史"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (144, '滁州西涧', '韦应物', '唐', '独怜幽草涧边生，上有黄鹂深树鸣。春潮带雨晚来急，野渡无人舟自横。', '', '滁州西涧描写了春天、山水等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人韦应物的作品。读的时候可以先抓住“春天、山水、雨”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“春天、山水、雨”主题。', 2, 2, '["春天", "山水", "雨"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (145, '秋思', '张籍', '唐', '洛阳城里见秋风，欲作家书意万重。复恐匆匆说不尽，行人临发又开封。', '', '秋思描写了思乡、秋天等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人张籍的作品。读的时候可以先抓住“思乡、秋天、亲情”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“思乡、秋天、亲情”主题。', 2, 2, '["思乡", "秋天", "亲情"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (146, '十五夜望月', '王建', '唐', '中庭地白树栖鸦，冷露无声湿桂花。今夜月明人尽望，不知秋思落谁家。', '', '十五夜望月描写了中秋、月夜等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王建的作品。读的时候可以先抓住“中秋、月夜、思乡”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“中秋、月夜、思乡”主题。', 2, 2, '["中秋", "月夜", "思乡"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (147, '雨过山村', '王建', '唐', '雨里鸡鸣一两家，竹溪村路板桥斜。妇姑相唤浴蚕去，闲看中庭栀子花。', '', '雨过山村描写了乡村、雨等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王建的作品。读的时候可以先抓住“乡村、雨、劳动”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“乡村、雨、劳动”主题。', 2, 2, '["乡村", "雨", "劳动"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (148, '新嫁娘词', '王建', '唐', '三日入厨下，洗手作羹汤。未谙姑食性，先遣小姑尝。', '', '新嫁娘词描写了生活、家庭等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王建的作品。读的时候可以先抓住“生活、家庭、习俗”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“生活、家庭、习俗”主题。', 2, 2, '["生活", "家庭", "习俗"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (149, '题李凝幽居', '贾岛', '唐', '闲居少邻并，草径入荒园。鸟宿池边树，僧敲月下门。', '', '题李凝幽居描写了月夜、山林等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人贾岛的作品。读的时候可以先抓住“月夜、山林、写作”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“月夜、山林、写作”主题。', 3, 3, '["月夜", "山林", "写作"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (150, '闺怨', '王昌龄', '唐', '闺中少妇不知愁，春日凝妆上翠楼。忽见陌头杨柳色，悔教夫婿觅封侯。', '', '闺怨描写了春天、思念等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王昌龄的作品。读的时候可以先抓住“春天、思念、边塞”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“春天、思念、边塞”主题。', 3, 3, '["春天", "思念", "边塞"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (151, '芙蓉楼送辛渐', '王昌龄', '唐', '寒雨连江夜入吴，平明送客楚山孤。洛阳亲友如相问，一片冰心在玉壶。', '', '芙蓉楼送辛渐描写了送别、友情等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王昌龄的作品。读的时候可以先抓住“送别、友情、品格”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“送别、友情、品格”主题。', 2, 2, '["送别", "友情", "品格"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (152, '采莲曲', '王昌龄', '唐', '荷叶罗裙一色裁，芙蓉向脸两边开。乱入池中看不见，闻歌始觉有人来。', '', '采莲曲描写了夏天、荷花等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王昌龄的作品。读的时候可以先抓住“夏天、荷花、生活”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“夏天、荷花、生活”主题。', 2, 2, '["夏天", "荷花", "生活"]', 'summer', NULL, NULL, FALSE, FALSE, '[]'),
    (153, '凉州词', '王之涣', '唐', '黄河远上白云间，一片孤城万仞山。羌笛何须怨杨柳，春风不度玉门关。', '', '凉州词描写了边塞、黄河等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人王之涣的作品。读的时候可以先抓住“边塞、黄河、春天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“边塞、黄河、春天”主题。', 2, 2, '["边塞", "黄河", "春天"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (154, '渔歌子', '张志和', '唐', '西塞山前白鹭飞，桃花流水鳜鱼肥。青箬笠，绿蓑衣，斜风细雨不须归。', '', '渔歌子描写了春天、江河等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人张志和的作品。读的时候可以先抓住“春天、江河、田园”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“春天、江河、田园”主题。', 2, 2, '["春天", "江河", "田园"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (155, '江南逢李龟年', '杜甫', '唐', '岐王宅里寻常见，崔九堂前几度闻。正是江南好风景，落花时节又逢君。', '', '江南逢李龟年描写了江南、友情等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜甫的作品。读的时候可以先抓住“江南、友情、春天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“江南、友情、春天”主题。', 2, 2, '["江南", "友情", "春天"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (156, '月夜忆舍弟', '杜甫', '唐', '戍鼓断人行，边秋一雁声。露从今夜白，月是故乡明。', '', '月夜忆舍弟描写了思乡、亲情等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜甫的作品。读的时候可以先抓住“思乡、亲情、秋天”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“思乡、亲情、秋天”主题。', 3, 3, '["思乡", "亲情", "秋天"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (157, '八阵图', '杜甫', '唐', '功盖三分国，名成八阵图。江流石不转，遗恨失吞吴。', '', '八阵图描写了历史、三国等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜甫的作品。读的时候可以先抓住“历史、三国、哲理”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“历史、三国、哲理”主题。', 2, 2, '["历史", "三国", "哲理"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (158, '前出塞', '杜甫', '唐', '挽弓当挽强，用箭当用长。射人先射马，擒贼先擒王。', '', '前出塞描写了边塞、战争等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜甫的作品。读的时候可以先抓住“边塞、战争、策略”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“边塞、战争、策略”主题。', 3, 3, '["边塞", "战争", "策略"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (159, '赠花卿', '杜甫', '唐', '锦城丝管日纷纷，半入江风半入云。此曲只应天上有，人间能得几回闻。', '', '赠花卿描写了音乐、成都等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜甫的作品。读的时候可以先抓住“音乐、成都、赞美”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“音乐、成都、赞美”主题。', 2, 2, '["音乐", "成都", "赞美"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (160, '江村', '杜甫', '唐', '清江一曲抱村流，长夏江村事事幽。自去自来梁上燕，相亲相近水中鸥。', '', '江村描写了夏天、乡村等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜甫的作品。读的时候可以先抓住“夏天、乡村、江河”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“夏天、乡村、江河”主题。', 3, 3, '["夏天", "乡村", "江河"]', 'summer', NULL, NULL, FALSE, FALSE, '[]'),
    (161, '春夜喜雨', '杜甫', '唐', '好雨知时节，当春乃发生。随风潜入夜，润物细无声。', '', '春夜喜雨描写了春天、雨等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜甫的作品。读的时候可以先抓住“春天、雨、自然”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“春天、雨、自然”主题。', 1, 1, '["春天", "雨", "自然"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (162, '闻官军收河南河北', '杜甫', '唐', '剑外忽传收蓟北，初闻涕泪满衣裳。却看妻子愁何在，漫卷诗书喜欲狂。', '', '闻官军收河南河北描写了家国、喜悦等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜甫的作品。读的时候可以先抓住“家国、喜悦、战争”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“家国、喜悦、战争”主题。', 3, 3, '["家国", "喜悦", "战争"]', 'any', NULL, NULL, FALSE, FALSE, '[]'),
    (163, '江畔独步寻花其六', '杜甫', '唐', '黄四娘家花满蹊，千朵万朵压枝低。留连戏蝶时时舞，自在娇莺恰恰啼。', '', '江畔独步寻花其六描写了春天、花等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人杜甫的作品。读的时候可以先抓住“春天、花、动物”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“春天、花、动物”主题。', 1, 1, '["春天", "花", "动物"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (164, '大林寺桃花', '白居易', '唐', '人间四月芳菲尽，山寺桃花始盛开。长恨春归无觅处，不知转入此中来。', '', '大林寺桃花描写了春天、桃花等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人白居易的作品。读的时候可以先抓住“春天、桃花、山寺”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“春天、桃花、山寺”主题。', 2, 2, '["春天", "桃花", "山寺"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (165, '暮江吟', '白居易', '唐', '一道残阳铺水中，半江瑟瑟半江红。可怜九月初三夜，露似真珠月似弓。', '', '暮江吟描写了秋天、江河等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人白居易的作品。读的时候可以先抓住“秋天、江河、月夜”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“秋天、江河、月夜”主题。', 1, 1, '["秋天", "江河", "月夜"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (166, '钱塘湖春行', '白居易', '唐', '孤山寺北贾亭西，水面初平云脚低。几处早莺争暖树，谁家新燕啄春泥。', '', '钱塘湖春行描写了春天、西湖等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人白居易的作品。读的时候可以先抓住“春天、西湖、动物”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“春天、西湖、动物”主题。', 3, 3, '["春天", "西湖", "动物"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (167, '问刘十九', '白居易', '唐', '绿蚁新醅酒，红泥小火炉。晚来天欲雪，能饮一杯无。', '', '问刘十九描写了冬天、友情等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人白居易的作品。读的时候可以先抓住“冬天、友情、生活”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“冬天、友情、生活”主题。', 2, 2, '["冬天", "友情", "生活"]', 'winter', NULL, NULL, FALSE, FALSE, '[]'),
    (168, '遗爱寺', '白居易', '唐', '弄石临溪坐，寻花绕寺行。时时闻鸟语，处处是泉声。', '', '遗爱寺描写了山水、花鸟等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人白居易的作品。读的时候可以先抓住“山水、花鸟、闲适”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“山水、花鸟、闲适”主题。', 1, 1, '["山水", "花鸟", "闲适"]', 'spring', NULL, NULL, FALSE, FALSE, '[]'),
    (169, '村夜', '白居易', '唐', '霜草苍苍虫切切，村南村北行人绝。独出门前望野田，月明荞麦花如雪。', '', '村夜描写了秋天、月夜等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人白居易的作品。读的时候可以先抓住“秋天、月夜、乡村”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“秋天、月夜、乡村”主题。', 2, 2, '["秋天", "月夜", "乡村"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (170, '菊花', '元稹', '唐', '秋丛绕舍似陶家，遍绕篱边日渐斜。不是花中偏爱菊，此花开尽更无花。', '', '菊花描写了秋天、菊花等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人元稹的作品。读的时候可以先抓住“秋天、菊花、品格”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“秋天、菊花、品格”主题。', 1, 1, '["秋天", "菊花", "品格"]', 'autumn', NULL, NULL, FALSE, FALSE, '[]'),
    (171, '离思', '元稹', '唐', '曾经沧海难为水，除却巫山不是云。取次花丛懒回顾，半缘修道半缘君。', '', '离思描写了情感、人生等画面或情感，适合孩子先从画面理解诗意。', '这首诗是唐代诗人元稹的作品。读的时候可以先抓住“情感、人生、哲理”这些关键词，再体会诗中的场景和心情。', '可以让孩子先找出诗里最有画面感的词句，再问：你看到了什么？听到了什么？诗人可能是什么心情？这首诗可归入“情感、人生、哲理”主题。', 3, 3, '["情感", "人生", "哲理"]', 'any', NULL, NULL, FALSE, FALSE, '[]')
ON CONFLICT (id) DO NOTHING;
